var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"기각할게.","JPN":"却下ね。","ENG":"Dismissed.","TWN":"駁回。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"어째서죠? 다들 똑똑히 봤다잖습니까!","JPN":"どうしてです？　みんなはっきりと見たって言ってるのに！","ENG":"But why? Everyone saw it as clear as day!","TWN":"為什麼？大家明明都有看到！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"낙인이 찍힌 반역자를 이대로 내버려뒀다간 예언대로 그루터기는 파국을 피할 수 없을 겁니다!","JPN":"烙印が押された反逆者をこのまま放っておくと、予言どおり切り株は破局に向かいます！","ENG":"If we leave that branded traitor be, the Stump will crumble just as prophesized!","TWN":"如果就這樣放任被打上烙印的叛徒不管，按照預言，木墩將發生無法避免災難！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이는 이곳에 머무르는 짧은 시간동안 그루터기에 많은 공헌을 했어.","JPN":"あの子はここにいる間、切り株にたくさん貢献したわ。","ENG":"That child has contributed a lot to the Stump in the short amount of time she was here.","TWN":"那個孩子在這裡停留的短暫時間裡，為木墩做出了很多貢獻。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그건 너희도 잘 알고 있지 않니?","JPN":"それはアナタたちもよく知っているでしょう？","ENG":"You all should know that too, do you not?","TWN":"這些你們也很清楚，不是嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"하지만 그 존재가 악마에게 영혼을 팔고 세상에 종말을 불러오는 존재가 된다면, 그런 공헌들이 무슨 의미가 있죠?","JPN":"でも、その存在が悪魔に魂を売って世界を終末に招く存在になるなら、そんな貢献に何の意味があるんですか？","ENG":"But if she really does sell her soul to a devil and bring about the apocalypse, what meaning will her contributions have?","TWN":"但是如果那個人出賣靈魂給魔鬼，成為帶來世界末日的存在，那些貢獻又有什麼意義呢？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"그루터기가 지금껏 예언을 가르치고 따라온 건, 그 예언에 마땅히 대비하기 위해서잖습니까?","JPN":"切り株が今まで予言を教え、従ってきた理由は、その予言に備えるためじゃないですか。","ENG":"Wasn't the reason for the Stump's teaching and following the prophecy to prepare for it?","TWN":"是啊！木墩至今教導和遵循著預言，不就是為了預防那個預言嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"대비라고?","JPN":"備える？","ENG":"Prepare?","TWN":"預防嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"내가 보기에 너흰 그저, 두려워하고 있을 뿐인걸?","JPN":"アタシが見るに、アナタたちはただ怯えているだけよ。","ENG":"All I see is fear in your eyes.","TWN":"在我看來，你們只是在害怕而已。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"인간에겐 스스로 사고하고 결정하는 힘이 있어. 그 아이가 정말로 위험한 존재인지는 좀 더 지켜봐도 늦지 않아.","JPN":"人間には自ら思考し、決定する力があるわ。あの子が本当に危険な存在なのかもう少し見守っても遅くはないはずよ。","ENG":"Humans have the power to think and decide for themselves. It is not too late to see if that child truly is a danger to us or not.","TWN":"人類有自己思考和決策的能力。那孩子是否真的危險，還可以再觀察一下。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희가 말하는 종말의 예언에서도, 그 아이가 너희를 몰살시킬 거란 구절은 없었잖아?","JPN":"アナタたちの言う終末の予言にも、あの子がアナタたちを皆殺しにするなんて一節はなかったでしょう？","ENG":"Even in the Apocalypse Augury you speak of, there is no mention of that child massacring you, is there?","TWN":"就算在你們所擔心的末日預言中，也沒有提到那孩子會將大家滅絕，不是嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"하지만 그 추측이 틀렸을 때의 대가는 종말이잖습니까!","JPN":"しかし、その推測が間違った時の代償は終末ですよ！","ENG":"But the price we'll have to pay if that assumption is wrong will be the end of the world!","TWN":"但如果猜錯了，代價就是末日！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"누구보다 낙원문을 완성하고 싶어하는 분께서, 그런 안일한 판단을 하시는 건가요?!","JPN":"誰よりも楽園の門の完成を望んでいる人が、どうしてそんな愚かな判断をするのです！？","ENG":"For someone who has been wanting to complete Avalon's Gate, how can you be so reckless with your decisions?!","TWN":"比任何人都想完成樂園門的祭司長，竟然會做出如此輕率的判斷嗎？！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 낙원문의 완성을 위해 그 아이의 힘이 필요한 거야.","JPN":"その楽園の門を完成させるのに、あの子の力が必要なの。","ENG":"I need that child's strength to complete Avalon's Gate.","TWN":"需要她的力量才能完成樂園門。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러니 만약, 그 아이가 정말 우리에게 위험이 될 조짐을 보인다면…","JPN":"だからもし、あの子が本当にアタシたちにとって危険な存在になるようなら……","ENG":"Yet, if I do notice that the child will be of danger to us...","TWN":"所以，如果那孩子真的有對我們構成威脅的跡象…"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…그땐 내가 처리할게.","JPN":"……その時は、アタシが処理するわ。","ENG":"...then I shall deal with her myself.","TWN":"…那時我會處理的。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"부디 그 선택이 너무 늦지 않길 바라야겠군요.","JPN":"その判断が手遅れにならないことを祈ります。","ENG":"I just hope it won't be too late when you choose to do so.","TWN":"希望那個選擇不會太遲。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"제사장님, 모르가나 아가씨가 동토에서 돌아왔습니다.","JPN":"祭祀長、モルガナお嬢様が凍土から戻ってきました。","ENG":"High Priest, Miss Morgana has returned from the gelid lands.","TWN":"祭司長，莫甘娜小姐從凍土回來了。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"말씀하신 것처럼, 그 성자도 함께요.","JPN":"おっしゃったとおり、あの聖者も一緒です。","ENG":"As you expected, the Helgon is with her.","TWN":"正如祭司長所說，那位聖者也一同回來了。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"콜록 콜록… 문만 열었는데도 무슨 먼지가 이렇게 날려?","JPN":"ゲホッ、ゲホッ……ドアを開けただけなのに、なんて埃なの。","ENG":"*Cough* *Cough* Why is so much dust flying from just opening the door?","TWN":"咳咳…只是開個門，怎麼會有這麼多灰塵？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"정말 이런 곳에서 지내도 괜찮겠어?","JPN":"本当にこんなところで暮らしても大丈夫？","ENG":"Are you sure about staying in a place like this?","TWN":"你真的準備在這種地方生活嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네, 동토 한복판에서 모닥불을 피우는 것보단 훨씬 형편이 좋은데요?","JPN":"はい、凍土の真ん中で焚火をしているよりはずっとましですよ。","ENG":"Yes. It's way better than just having a campfire in the middle of the gelid lands, no?","TWN":"沒錯，比起在凍土升營火，這裡已經好很多了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이 숲은 마을에서 동떨어진 외곽지야.","JPN":"この森は、村から離れてる外郭だよ。","ENG":"This forest is on the outskirts of the village.","TWN":"這片森林是遠離村莊的邊緣地帶。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"파수대가 순찰을 돌지도 않는 곳이라, 언제 뭐가 나타나건 혼자 해결해야 한다구.","JPN":"見張隊も巡回しない場所だから、いつ何が現われても自分で解決しないとダメなんだよ？","ENG":"Not even the sentinels patrol here. So if anything happens, you'll have to handle it yourself.","TWN":"這裡是巡邏隊也不會路過的地方，出現什麼東西都得自己解決。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"괜찮아요.","JPN":"大丈夫です。","ENG":"I know.","TWN":"沒關係。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마물이 정말로 저 때문에 나타나는 거라면, 이렇게 떨어져 지내는 편이 모두를 위한 일이니까요.","JPN":"本当に私のせいで魔物が現われるのなら、こうやって離れたところで暮らした方がみんなのためですから。","ENG":"But if the monsters are really approaching here because of me, it would be better if I kept my distance like this.","TWN":"如果怪物真的是因為我而出現的，那這樣遠離大家生活對所有人都好。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};